def _clean_composite_fields(self):
    for validator in self.composite_validators:
        if not isinstance(validator, CompositFieldValidator):
            raise TypeError(
                "All entries in composite_validators must be "
                "CompositFieldValidator instances, got %r." % type(validator)
            )
        for field_name in validator.fields:
            if field_name not in self.fields:
                raise ValueError(
                    "CompositFieldValidator references field '%s' which "
                    "does not exist on %s."
